mapper.select:
select fi.*
from scheduler_flow_instance_his fi



            and (fi.flow_name like concat('%', #{query.flowKeyword}, '%')
                or fi.id::text = #{query.flowKeyword}
                or fi.flow_id::text = #{query.flowKeyword})


            and exists (
                select 1
                from scheduler_task_instance_his ti
                where ti.flow_instance_id = fi.id
                  and (ti.task_name like concat('%', #{query.taskKeyword}, '%')
                    or ti.id::text = #{query.taskKeyword}
                    or ti.task_id::text = #{query.taskKeyword})
            )


            and fi.status = #{query.status}


            and fi.schedule_time >= #{query.scheduleStartTime}


            and fi.schedule_time <= #{query.scheduleEndTime}


            and fi.start_time >= #{query.startTime}


            and fi.start_time <= #{query.endTime}


            and fi.end_time >= #{query.finishStartTime}


            and fi.end_time <= #{query.finishEndTime}



order by fi.schedule_time desc nulls last, fi.create_time desc

mapper.insert:
insert into scheduler_flow_instance_his ( id, flow_id, flow_name, flow_code, flow_type, status, trigger_id, publish_version, flow_param, dep_event_ids, event_id, schedule_time, start_time, end_time, creator, updater, create_time, update_time, flow_dag_snapshot ) select id, flow_id, flow_name, flow_code, flow_type, status, trigger_id, publish_version, flow_param, dep_event_ids, event_id, schedule_time, start_time, end_time, creator, updater, create_time, update_time, flow_dag_snapshot from scheduler_flow_instance where id in
#{instanceId}
on conflict (id) do nothing
